----------------------------------------------------

Then, if set == oset, set argument was override before use it at (1).
To introduce temporary variable fix this issue easily.
How-To-Repeat: run following program

------------------------------------------------------
#include <pthread.h>
#include <signal.h>
#include <stdio.h>

void* func(void* arg)
{
        sigset_t old;
        sigset_t add;
        int i;

        sigemptyset(&old);
        pthread_sigmask(SIG_BLOCK, NULL, &old);

        printf("before: ");
        for (i=0; i<4; i++)
                printf(" %08x", old.__bits[i]);
        printf("\n");

        sigemptyset(&add);
        sigaddset(&add, SIGUSR1);
        pthread_sigmask(SIG_BLOCK, &add, NULL);
        pthread_sigmask(SIG_BLOCK, NULL, &old);

        printf("after:  ");
        for (i=0; i<4; i++)
                printf(" %08x", old.__bits[i]);
        printf("\n");

        return 0;
}

void* func2(void* arg)
{
        sigset_t old;
        sigset_t add;
        int i;

        sigemptyset(&old);
        pthread_sigmask(SIG_BLOCK, NULL, &old);

        printf("before: ");
        for (i=0; i<4; i++)
                printf(" %08x", old.__bits[i]);
        printf("\n");

        sigemptyset(&add);
        sigaddset(&add, SIGUSR1);
        pthread_sigmask(SIG_BLOCK, &add, &old);

        printf("after:  ");
        for (i=0; i<4; i++)
                printf(" %08x", old.__bits[i]);
        printf("\n");

        return 0;
}

int main(void)
{
        pthread_t thr;
        void* ret;

        printf("correct case: \n");
        pthread_create(&thr, NULL, func, NULL);
        pthread_join(thr, &ret);

        printf("incorrect case: \n");
        pthread_create(&thr, NULL, func2, NULL);
        pthread_join(thr, &ret);


        return 0;
}
